import torch
import torch.nn as nn
import torch.nn.functional as F
import torch.distributed as dist


def _world_size():
    return dist.get_world_size() if dist.is_available() and dist.is_initialized() else 1


def _rank():
    return dist.get_rank() if dist.is_available() and dist.is_initialized() else 0


class _AllGather(torch.autograd.Function):
    @staticmethod
    def forward(ctx, input_):
        world_size = _world_size()
        if world_size == 1:
            return input_
        input_ = input_.contiguous()
        tensors = [torch.empty_like(input_) for _ in range(world_size)]
        dist.all_gather(tensors, input_)
        return torch.cat(tensors, dim=-1)

    @staticmethod
    def backward(ctx, grad_output):
        world_size = _world_size()
        if world_size == 1:
            return grad_output
        rank = _rank()
        return grad_output.chunk(world_size, dim=-1)[rank].contiguous()


class _AllReduce(torch.autograd.Function):
    @staticmethod
    def forward(ctx, input_):
        world_size = _world_size()
        if world_size == 1:
            return input_
        out = input_.clone()
        dist.all_reduce(out)
        return out

    @staticmethod
    def backward(ctx, grad_output):
        return grad_output


class ColumnParallelLinear(nn.Module):
    def __init__(self, in_features, out_features, bias, master_weight):
        super().__init__()
        world_size = _world_size()
        rank = _rank()
        assert out_features % world_size == 0, \
            "out_features must be divisible by world_size"
        self.in_features = in_features
        self.out_features = out_features
        self.local_out = out_features // world_size
        start = rank * self.local_out
        end = start + self.local_out
        w = master_weight[start:end, :].detach().clone()
        self.weight = nn.Parameter(w)
        if bias:
            self.bias = nn.Parameter(torch.zeros(self.local_out,
                                                 dtype=w.dtype))
        else:
            self.register_parameter('bias', None)

    def forward(self, x):
        y = F.linear(x, self.weight, self.bias)
        return _AllGather.apply(y)


class RowParallelLinear(nn.Module):
    def __init__(self, in_features, out_features, bias, master_weight):
        super().__init__()
        world_size = _world_size()
        rank = _rank()
        assert in_features % world_size == 0, \
            "in_features must be divisible by world_size"
        self.in_features = in_features
        self.out_features = out_features
        self.local_in = in_features // world_size
        start = rank * self.local_in
        end = start + self.local_in
        w = master_weight[:, start:end].detach().clone()
        self.weight = nn.Parameter(w)
        if bias:
            self.bias = nn.Parameter(torch.zeros(out_features, dtype=w.dtype))
        else:
            self.register_parameter('bias', None)

    def forward(self, x):
        y = F.linear(x, self.weight)
        y = _AllReduce.apply(y)
        if self.bias is not None:
            y = y + self.bias
        return y
